void sysclk_config(){

	RCC->CR |=HSEON;//HSE clock enable
	while(!(RCC->CR & HSERDY)); // wait for HSE clock ready flag


	RCC->APB1ENR |=I2C1_EN;// enable 12c1 interface

	RCC->APB1ENR |=PWR_CLK; //Power interface clock enable
	PWR_ON();

	*(FLASH.ACR) |= ICEN | DCEN | PRFTEN | LATENCY ; //configure flash for 5cpu cycle latency

	RCC->PLLCFGR |=(PLLM | PLLN | PLLSRC | PLLP | PLLQ); //sets clock frequency
	RCC->CR |= PLLON;//Main PLL (PLL) enable

	while(!(RCC->CR & PLLRDY)); //wait for Main PLL (PLL) clock ready

	RCC->CFGR |=  MAIN_PRE;
	RCC->CFGR &= ~CLOCK_SWITCH; // clear switch clock bit
	RCC->CFGR |= PLL_AS_MAIN; // set pll clock as main clock

	while((RCC->CFGR & SWITCH_STATUS) != (2U << 2)); // verify the clock is switched or not

}
