uint8_t get_pos(uint16_t pin){
	uint8_t i=0;
	while(pin > 1){
		pin=pin/2;
		i++;
	}
	return i;
}
void GPIOx_init(){
	RCC->AHB1ENR |= GPIOA_EN |GPIOB_EN; //enable clock for GPIOA and GPIOB

	GPIO_pin_init(I2C1_PORT, I2C1_SDA, AF_PP);
	GPIO_pin_init(I2C1_PORT, I2C1_SCL, AF_PP);
//	GPIO_pin_init(LED_PORT,LED_PIN,OUTPUT_NOPULL);
}

void GPIO_pin_init(GPIO_TypeDef *GPIOx,uint16_t pin,enum _mode mode){
	uint8_t pos=get_pos(pin);
	if(mode == AF_PP){
	GPIOx->MODER |= (_AF << (2*pos)); // selects gpio mode
	GPIOx->OTYPER |= (1U << pos); // 1 for open drain 0 for push pull
	GPIOx->PUPDR |= (_PU << (2*pos)); // pull up or pull down

	uint8_t af_index = (pos > 7)? 1:0;
	GPIOx->AFR[af_index] |= (4U << ((pos % 8)  *4)); //set pin to alternate function
	}else if(mode == INPUT_NOPULL){
		GPIOx->MODER |= (_INPUT << (2*pos));
		GPIOx->PUPDR |= (_PP << (2*pos)); // pull up or pull down
	}else if(mode == OUTPUT_NOPULL){
		GPIOx->MODER |= (_OUTPUT << (2*pos));
		GPIOx->PUPDR |= (_PP << (2*pos)); // pull up or pull down

	}else if(mode == OUTPUT_PU){
		GPIOx->MODER |= (_INPUT << (2*pos));
		GPIOx->PUPDR |= (_PU << (2*pos)); // pull up or pull down
	}else if(mode == INPUT_PU){
		GPIOx->MODER |= (_INPUT << (2*pos));
		GPIOx->PUPDR |= (_PU << (2*pos)); // pull up or pull down
	}
}
